import { Component } from '@angular/core';

@Component({
  selector: 'app-root',
  templateUrl: 'app.component.html',
  styleUrls: ['app.component.scss'],
  standalone: false,
})
export class AppComponent {
  constructor() {}
}
<ion-app>
  <ion-header>
    <ion-toolbar>
      <ion-button>logo will go here</ion-button>
      <ion-button>our story</ion-button>
      <ion-button>programs</ion-button>
      <ion-button>news/events</ion-button>
      <ion-button>search bar?</ion-button>
      <ion-button>donate</ion-button>
    </ion-toolbar>
  </ion-header>
  <ion-router-outlet></ion-router-outlet>
</ion-app>
